import React, { useEffect, useState } from "react";
import { Card, Row, Col, Badge, Modal, Button } from "react-bootstrap";
import { Store, Users, AlertTriangle } from "lucide-react";
import { searchDocuments } from "../api";

const MANDATORY_DOCS = [
  "ID Proof",
  "Address Proof",
  "Educational Certificate",
  "Employment Contract",
];

const getStatus = (expiryDate) => {
  if (!expiryDate) return "valid";
  const days =
    (new Date(expiryDate) - new Date()) / (1000 * 60 * 60 * 24);

  if (days <= 0) return "expired";
  if (days <= 30) return "expiring";
  return "valid";
};

const ComplianceDashboard = () => {
  const [stores, setStores] = useState([]);
  const [selectedStore, setSelectedStore] = useState(null);

  useEffect(() => {
    loadDashboard();
  }, []);

  const loadDashboard = async () => {
    const res = await searchDocuments({});
    const documents = res?.data?.data || [];

    const storeMap = {};
    let overallStats = {
      total: 0,
      valid: 0,
      expiring: 0,
      expired: 0,
      missing: 0,
    };

    documents.forEach((doc) => {
      const status = getStatus(doc.expiryDate);

      if (!storeMap[doc.store]) {
        storeMap[doc.store] = {
          store: doc.store,
          total: 0,
          valid: 0,
          expiring: 0,
          expired: 0,
          employees: {},
        };
      }

      storeMap[doc.store].total++;
      overallStats.total++;

      storeMap[doc.store][status]++;
      overallStats[status]++;

      if (!storeMap[doc.store].employees[doc.employeeId]) {
        storeMap[doc.store].employees[doc.employeeId] = {
          name: doc.employeeName,
          documents: [],
        };
      }

      storeMap[doc.store].employees[doc.employeeId].documents.push({
        type: doc.documentType,
        status,
      });
    });

    /* MISSING DOCUMENT CALCULATION */
    Object.values(storeMap).forEach((store) => {
      Object.values(store.employees).forEach((emp) => {
        const uploaded = emp.documents.map((d) => d.type);
        const missing = MANDATORY_DOCS.filter(
          (d) => !uploaded.includes(d)
        );

        emp.missing = missing;
        store.missing += missing.length;
        overallStats.missing += missing.length;
      });

      store.compliance = store.total
        ? Math.round((store.valid / store.total) * 100)
        : 0;
    });

    setStores(Object.values(storeMap));
  };

  return (
    <div className="p-4">
      <h3 className="mb-4">
        <Store size={22} className="me-2" />
        Overall Compliance Dashboard
      </h3>

      {/* ================= OVERALL STATS ================= */}
      <Row className="mb-4">
        <Col><Card body>📄 Total Docs <h4>{stores.reduce((a,b)=>a+b.total,0)}</h4></Card></Col>
        <Col><Card body className="text-success">🟢 Valid <h4>{stores.reduce((a,b)=>a+b.valid,0)}</h4></Card></Col>
        <Col><Card body className="text-warning">🟡 Expiring <h4>{stores.reduce((a,b)=>a+b.expiring,0)}</h4></Card></Col>
        <Col><Card body className="text-danger">🔴 Expired <h4>{stores.reduce((a,b)=>a+b.expired,0)}</h4></Card></Col>
        <Col><Card body>⚪ Missing <h4>{stores.reduce((a,b)=>a+b.missing,0)}</h4></Card></Col>
      </Row>

      {/* ================= STORE CARDS ================= */}
      <Row className="g-4">
        {stores.map((store) => (
          <Col md={3} key={store.store}>
            <Card
              className="h-100 text-center"
              onClick={() => setSelectedStore(store)}
              style={{ cursor: "pointer" }}
            >
              <Card.Body>
                <h5>{store.store}</h5>

                <h2
                  className={
                    store.compliance >= 75
                      ? "text-success"
                      : store.compliance >= 50
                      ? "text-warning"
                      : "text-danger"
                  }
                >
                  {store.compliance}%
                </h2>

                <small>Document Compliance</small>

                <div className="mt-3">
                  <Badge bg="success" className="me-1">
                    Valid: {store.valid}
                  </Badge>
                  <Badge bg="warning" className="me-1">
                    Exp: {store.expiring}
                  </Badge>
                  <Badge bg="danger">
                    Expired: {store.expired}
                  </Badge>
                </div>
              </Card.Body>
            </Card>
          </Col>
        ))}
      </Row>

      {/* ================= STORE DETAIL ================= */}
      <Modal
        show={!!selectedStore}
        onHide={() => setSelectedStore(null)}
        size="lg"
      >
        {selectedStore && (
          <>
            <Modal.Header closeButton>
              <Modal.Title>
                <Users size={18} className="me-2" />
                {selectedStore.store} – Employees
              </Modal.Title>
            </Modal.Header>

            <Modal.Body>
              {Object.values(selectedStore.employees).map((emp, i) => (
                <Card key={i} className="mb-2">
                  <Card.Body>
                    <strong>{emp.name}</strong>
                    <div className="mt-2">
                      {emp.documents.map((d, idx) => (
                        <Badge
                          key={idx}
                          bg={
                            d.status === "valid"
                              ? "success"
                              : d.status === "expiring"
                              ? "warning"
                              : "danger"
                          }
                          className="me-1"
                        >
                          {d.type}
                        </Badge>
                      ))}
                    </div>

                    {emp.missing.length > 0 && (
                      <div className="text-danger mt-2">
                        <AlertTriangle size={14} /> Missing:{" "}
                        {emp.missing.join(", ")}
                      </div>
                    )}
                  </Card.Body>
                </Card>
              ))}
            </Modal.Body>
          </>
        )}
      </Modal>
    </div>
  );
};

export default ComplianceDashboard;
